+            counter += 1;
+        });
+    });
+
+    group.finish();
+}
+
+// =============================================================================
+// Criterion Groups
+// =============================================================================
+
+criterion_group!(
+    storage_benches,
+    bench_create_single,
+    bench_create_batch,
+    bench_list_issues,
+    bench_ready_query,
+    bench_blocked_query,
+    bench_add_dependency,
+);
+
+criterion_group!(sync_benches, bench_export, bench_import,);
+
+criterion_main!(storage_benches, sync_benches);

